24: /**
25:  * The method to use for pricing FX vanilla options.
26:  * <p>
27:  * This provides the ability to use different methods for pricing FX options.
28:  * The Black and Vanna-Volga methods are supported.
29:  * <p>
30:  * This enum implements {@link CalculationParameter} and is used by passing it
31:  * as an argument to {@link CalculationRules}. It provides the link between the
32:  * data that the function needs and the data that is available in {@link ScenarioMarketData}.
33:  * <p>
34:  * Implementations of this interface must be immutable.
35:  */
36: public enum FxVanillaOptionMethod implements NamedEnum, CalculationParameter {
37: 
38:   /**
39:    * The Black (lognormal) model.
40:    * This uses Black volatilities - {@link BlackFxOptionVolatilities}.
41:    */
42:   BLACK,
43:   /**
44:    * The Vanna-Volga model.
45:    * This uses Black volatilities based on a smile - {@link BlackFxOptionSmileVolatilities}.
46:    */
47:   VANNA_VOLGA;
48: 
49:   // helper for name conversions
50:   private static final EnumNames<FxVanillaOptionMethod> NAMES = EnumNames.of(FxVanillaOptionMethod.class);
51: 
52:   //-------------------------------------------------------------------------
53:   /**
54:    * Obtains an instance from the specified name.
55:    * <p>
56:    * Parsing handles the mixed case form produced by {@link #toString()} and
57:    * the upper and lower case variants of the enum constant name.
58:    * 
59:    * @param name  the name to parse
60:    * @return the type
61:    * @throws IllegalArgumentException if the name is not known
62:    */
63:   @FromString
64:   public static FxVanillaOptionMethod of(String name) {
65:     return NAMES.parse(name);
66:   }
67: 
68:   //-------------------------------------------------------------------------
69:   @Override
70:   public Optional<CalculationParameter> filter(CalculationTarget target, Measure measure) {
71:     if (target instanceof FxVanillaOptionTrade) {
72:       return Optional.of(this);
73:     }
74:     return Optional.empty();
75:   };
76: 
77:   //-------------------------------------------------------------------------
78:   /**
79:    * Returns the formatted name of the type.
80:    * 
81:    * @return the formatted string representing the type
82:    */
83:   @ToString
84:   @Override
85:   public String toString() {
86:     return NAMES.format(this);
87:   }
88: 
89: }
